+type DisableScope = {
+  allRules: boolean,
+  disabledRules: Set<string>,
+  enabledRules: Set<string>,
+};
+
+type Marker = {
+  action: 'disable' | 'enable' | 'next',
+  ruleNames?: string[],
+  lineCount?: number,
+};
+
+const markerRegex = /^[ \	]*(?:<!--[ \	]*linter-(disable-next-n-lines[ \	]*:[ \	]*[^ \	]+(?:[ \	]+.*?)?|disable-next-line(?:[ \	]+.*?)?|disable(?:[ \	]+.*?)?|enable(?:[ \	]+.*?)?)[ \	]*-->|%%[ \	]*linter-(disable-next-n-lines[ \	]*:[ \	]*[^ \	]+(?:[ \	]+.*?)?|disable-next-line(?:[ \	]+.*?)?|disable(?:[ \	]+.*?)?|enable(?:[ \	]+.*?)?)[ \	]*%%)[ \	]*$/i;
+
+/**
+ * Protects linter directive lines and the lines disabled for one rule while a
+ * rule runs. Directives are intentionally parsed from the current text on
+ * each run: earlier rules may change surrounding content, but never directives.
+ */
+export function ignoreScopedRuleSections(text: string, ruleAlias: string, isKnownRule: (alias: string) => boolean, func: (text: string) => string): string {
+  const lines = text.split('\
');
+  const unavailableLines = getUnavailableLines(text);
+  const protectedLines = new Set<number>();
+  const scopes: DisableScope[] = [];
+  const lineScopedDisables = new Set<number>();
+
+  for (let lineIndex = 0; lineIndex < lines.length; lineIndex++) {
+    if (lineScopedDisables.has(lineIndex) || scopes.some((scope) => scopeDisablesRule(scope, ruleAlias))) {
+      protectedLines.add(lineIndex);
+    }
+
+    if (unavailableLines.has(lineIndex)) {
+      continue;
+    }
+
+    const marker = parseMarker(lines[lineIndex], isKnownRule);
+    if (marker === null) {
+      continue;
+    }
+
+    // Directives themselves are always preserved, including ones with invalid
+    // rule names or an invalid next-n-lines value.
+    protectedLines.add(lineIndex);
+    if (marker.action === 'disable') {
+      scopes.push({
+        allRules: marker.ruleNames === undefined,
+        disabledRules: new Set(marker.ruleNames ?? []),
+        enabledRules: new Set(),
+      });
+    } else if (marker.action === 'enable') {
+      if (marker.ruleNames === undefined) {
+        scopes.pop();
+      } else if (marker.ruleNames.includes(ruleAlias)) {
+        const scope = [...scopes].reverse().find((candidate) => scopeDisablesRule(candidate, ruleAlias));
+        if (scope) {
+          if (scope.allRules) {
+            scope.enabledRules.add(ruleAlias);
+          } else {
+            scope.disabledRules.delete(ruleAlias);
+            if (scope.disabledRules.size === 0) {
+              scopes.splice(scopes.indexOf(scope), 1);
+            }
+          }
+        }
+      }
+    } else if (marker.lineCount !== undefined) {
+      const finalLine = Math.min(lines.length - 1, lineIndex + marker.lineCount);
+      for (let ignoredLine = lineIndex + 1; ignoredLine <= finalLine; ignoredLine++) {
+        lineScopedDisables.add(ignoredLine);
+      }
+    }
+  }
+
+  return replaceProtectedLines(text, lines, protectedLines, func);
+}
+
+/** Protect directive lines for work that is not associated with a rule alias. */
+export function ignoreScopedRuleMarkers(text: string, func: (text: string) => string): string {
+  const lines = text.split('\
');
+  const unavailableLines = getUnavailableLines(text);
+  const protectedLines = new Set<number>();
+  for (let lineIndex = 0; lineIndex < lines.length; lineIndex++) {
+    if (!unavailableLines.has(lineIndex) && parseMarker(lines[lineIndex], () => true) !== null) {
+      protectedLines.add(lineIndex);
+    }
+  }
+
+  return replaceProtectedLines(text, lines, protectedLines, func);
+}
+
+function parseMarker(line: string, isKnownRule: (alias: string) => boolean): Marker | null {
+  const match = line.match(markerRegex);
+  if (match === null) {
+    return null;
+  }
+
+  const directive = (match[1] ?? match[2]).trim();
+  const nextNLinesMatch = directive.match(/^disable-next-n-lines[ \	]*:[ \	]*([^ \	]+)(?:[ \	]+(.*))?$/i);
+  if (nextNLinesMatch) {
+    if (!/^[1-9]\\d*$/.test(nextNLinesMatch[1])) {
+      return {action: 'next'};
+    }
+    const ruleNames = normalizeRuleNames(nextNLinesMatch[2], isKnownRule);
+    return ruleNames === null ? {action: 'next', lineCount: Number(nextNLinesMatch[1])} : ruleNames.length > 0 ? {action: 'next', ruleNames, lineCount: Number(nextNLinesMatch[1])} : {action: 'next'};
+  }
+
+  const nextLineMatch = directive.match(/^disable-next-line(?:[ \	]+(.*))?$/i);
+  if (nextLineMatch) {
+    const ruleNames = normalizeRuleNames(nextLineMatch[1], isKnownRule);
+    return ruleNames === null ? {action: 'next', lineCount: 1} : ruleNames.length > 0 ? {action: 'next', ruleNames, lineCount: 1} : {action: 'next'};
+  }
+
+  const disableOrEnableMatch = directive.match(/^(disable|enable)(?:[ \	]+(.*))?$/i);
+  if (disableOrEnableMatch === null) {
+    return null;
+  }
+  const ruleNames = normalizeRuleNames(disableOrEnableMatch[2], isKnownRule);
+  if (ruleNames !== null && ruleNames.length === 0) {
+    // An explicitly supplied, but empty/unknown-only list has no effect.
+    return {action: disableOrEnableMatch[1].toLowerCase() as 'disable' | 'enable', ruleNames: []};
+  }
+  return {action: disableOrEnableMatch[1].toLowerCase() as 'disable' | 'enable', ruleNames};
+}
+
+function normalizeRuleNames(value: string | undefined, isKnownRule: (alias: string) => boolean): string[] | null {
+  if (value === undefined) {
+    return null;
+  }
+  return [...new Set(value.split(',').map((name) => name.trim().toLowerCase()).filter((name) => name !== '' && isKnownRule(name)))];
+}
+
+function scopeDisablesRule(scope: DisableScope, ruleAlias: string): boolean {
+  return (scope.allRules && !scope.enabledRules.has(ruleAlias)) || scope.disabledRules.has(ruleAlias);
+}
+
+function getUnavailableLines(text: string): Set<number> {
+  const unavailableLines = new Set<number>();
+  const types = [MDAstTypes.Code, MDAstTypes.InlineCode, MDAstTypes.Math, MDAstTypes.InlineMath, 'yaml' as MDAstTypes];
+  for (const type of types) {
+    for (const position of getPositions(type, text)) {
+      for (let line = position.start.line - 1; line < position.end.line; line++) {
+        unavailableLines.add(line);
+      }
+    }
+  }
+  return unavailableLines;
+}
+
+function replaceProtectedLines(text: string, lines: string[], protectedLines: Set<number>, func: (text: string) => string): string {
+  if (protectedLines.size === 0) {
+    return func(text);
+  }
+  const values: string[] = [];
+  const protectedText = lines.map((line, index) => {
+    if (!protectedLines.has(index)) {
+      return line;
+    }
+    const placeholder = `{SCOPED_RULE_IGNORE_${values.length}}`;
+    values.push(line);
+    return placeholder;
+  }).join('\
');
+
+  let result = func(protectedText);
+  for (let index = 0; index < values.length; index++) {
+    result = result.replace(new RegExp(`\\\\{SCOPED_RULE_IGNORE_${index}\\\\}`, 'i'), values[index].replace(/\\$/g, '$$$$'));
+  }
+  return result;
+}
